        end else if (encode_en) begin
            codeword_out    <= {data_k, parity};
            data_out        <= 16'b0;
            error_detected  <= 1'b0;
            error_corrected <= 1'b0;
            valid_out       <= 1'b1;
        end else if (decode_en) begin
            codeword_out    <= 31'b0;
            data_out        <= corrected_cw[30:15];
            error_detected  <= any_syndrome;
            error_corrected <= any_syndrome;
            valid_out       <= 1'b1;
        end else begin
            valid_out       <= 1'b0;
        end
    end

endmodule
